import{_ as n,o as e,c as a,ag as i}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"04 — Lộ trình phát hành (Roadmap)","description":"","frontmatter":{},"headers":[],"relativePath":"00-san-pham/04-lo-trinh-phat-hanh.md","filePath":"00-san-pham/04-lo-trinh-phat-hanh.md"}'),o={name:"00-san-pham/04-lo-trinh-phat-hanh.md"};function r(d,t,h,s,l,c){return e(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="_04-—-lo-trinh-phat-hanh-roadmap" tabindex="-1">04 — Lộ trình phát hành (Roadmap) <a class="header-anchor" href="#_04-—-lo-trinh-phat-hanh-roadmap" aria-label="Permalink to &quot;04 — Lộ trình phát hành (Roadmap)&quot;">​</a></h1><blockquote><p><strong>Vai trò đọc</strong>: PO, PM, Scrum Master, Founder — biết &quot;đang ở đâu trong timeline, sắp tới làm gì&quot;. <strong>Cập nhật</strong>: PM update sau mỗi sprint retro. Mọi pivot scope/sequence phải log vào <code>99-tham-khao/changelog.md</code>.</p></blockquote><hr><h2 id="roadmap-tong-3-phase-18-thang" tabindex="-1">Roadmap tổng (3 phase, 18 tháng) <a class="header-anchor" href="#roadmap-tong-3-phase-18-thang" aria-label="Permalink to &quot;Roadmap tổng (3 phase, 18 tháng)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2026 ────────────────────────────────────────────────────► 2027 ───►  2028+</span></span>
<span class="line"><span> Q2          Q3            Q4              2027 Q1-Q2     Q3-Q4</span></span>
<span class="line"><span> │           │             │               │              │</span></span>
<span class="line"><span> │ Phase 1   │ Phase 1     │ Phase 1.5     │ Phase 2      │ Phase 3+</span></span>
<span class="line"><span> │ MVP build │ MVP launch  │ EN + loyalty  │ Affiliate +  │ Hotel portal</span></span>
<span class="line"><span> │           │ (beta)      │ + upsell      │ Mobile RN    │ lite, đa thị trường</span></span>
<span class="line"><span> ▼           ▼             ▼               ▼              ▼</span></span></code></pre></div><h3 id="phase-1-—-mvp-q2-q3-2026-3-6-thang" tabindex="-1">Phase 1 — MVP (Q2-Q3/2026, 3-6 tháng) <a class="header-anchor" href="#phase-1-—-mvp-q2-q3-2026-3-6-thang" aria-label="Permalink to &quot;Phase 1 — MVP (Q2-Q3/2026, 3-6 tháng)&quot;">​</a></h3><p><strong>Mục tiêu</strong>: Launch private beta tour operator B2C cho thị trường VN — book Series Tour online + lead capture Private Tour, có CMS đủ vận hành, SEO foundation, dashboard L0.</p><p><strong>Definition of Success</strong>:</p><ul><li>≥20 tour active trên web (Founder ký contract trước)</li><li>Booking flow happy-path không lỗi với 3 user thật private beta</li><li>SEO: sitemap động + 100% page có metadata + structured data</li><li>Admin tạo 1 tour mới &lt;5 phút (không cần dev support)</li><li>Tháng 6 sau launch đạt ≥50 booking/tháng (target — có thể điều chỉnh)</li></ul><h3 id="phase-1-5-—-hoan-thien-en-q4-2026" tabindex="-1">Phase 1.5 — Hoàn thiện &amp; EN (Q4/2026) <a class="header-anchor" href="#phase-1-5-—-hoan-thien-en-q4-2026" aria-label="Permalink to &quot;Phase 1.5 — Hoàn thiện &amp; EN (Q4/2026)&quot;">​</a></h3><p><strong>Mục tiêu</strong>: Mở rộng audience + tăng AOV + chuẩn bị traffic Phase 2.</p><table tabindex="0"><thead><tr><th>Module</th><th>Lý do</th></tr></thead><tbody><tr><td>EN landing + content tour quốc tế</td><td>Khách quốc tế ghé VN tăng → mở luồng EN</td></tr><tr><td>Loyalty cơ bản (point + voucher)</td><td>Repeat rate &gt;20% → ROI cao hơn acquire mới</td></tr><tr><td>Upsell (bảo hiểm, room upgrade, sân bay riêng)</td><td>Tăng AOV 15-25% không cần thêm tour</td></tr><tr><td>Self-service cancel theo policy</td><td>Giảm load support</td></tr><tr><td>Admin Dashboard L1 (conversion, AOV, retention)</td><td>Đo lường hiệu quả marketing</td></tr></tbody></table><h3 id="phase-2-—-scale-2027" tabindex="-1">Phase 2 — Scale (2027) <a class="header-anchor" href="#phase-2-—-scale-2027" aria-label="Permalink to &quot;Phase 2 — Scale (2027)&quot;">​</a></h3><p><strong>Mục tiêu</strong>: Tăng acquisition channel + chuyển mobile.</p><table tabindex="0"><thead><tr><th>Module</th><th>Lý do</th></tr></thead><tbody><tr><td>Affiliate / KOL referral</td><td>Acquire mới qua người nổi tiếng — không marketplace</td></tr><tr><td>Mobile app (React Native)</td><td>Khi web mobile đã chứng minh retention</td></tr><tr><td>Inventory tinh chỉnh (per-date allotment tracking)</td><td>Khi volume đủ để vận hành chi tiết hơn</td></tr><tr><td>Admin Dashboard L2 (P&amp;L tour, profit/tour)</td><td>Khi accounting đã ổn định</td></tr></tbody></table><h3 id="phase-3-—-mo-rong-2028" tabindex="-1">Phase 3+ — Mở rộng (2028+) <a class="header-anchor" href="#phase-3-—-mo-rong-2028" aria-label="Permalink to &quot;Phase 3+ — Mở rộng (2028+)&quot;">​</a></h3><ul><li>Hotel portal lite (vẫn không OTA — chỉ partner self-update info)</li><li>Đa thị trường (CN/JP nếu data ủng hộ)</li><li>Multi-tenant admin nếu acquire công ty khác</li><li><strong>Chưa committed</strong> — phụ thuộc Phase 1+2 outcome.</li></ul><hr><h2 id="sprint-roadmap-phase-1" tabindex="-1">Sprint roadmap Phase 1 <a class="header-anchor" href="#sprint-roadmap-phase-1" aria-label="Permalink to &quot;Sprint roadmap Phase 1&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SPRINT 1 ──► SPRINT 2 ──► SPRINT 3 ──► SPRINT 4 ──► SPRINT 5 ──► SPRINT 6</span></span>
<span class="line"><span>Foundation  CMS         Discovery    Booking      Member       Optimize</span></span>
<span class="line"><span>(Done)      (Done)      (Doing)      (Upcoming)   (Upcoming)   (Upcoming)</span></span></code></pre></div><h3 id="tang-1-—-foundation-sprint-1-2-done" tabindex="-1">Tầng 1 — Foundation (Sprint 1-2, Done) <a class="header-anchor" href="#tang-1-—-foundation-sprint-1-2-done" aria-label="Permalink to &quot;Tầng 1 — Foundation (Sprint 1-2, Done)&quot;">​</a></h3><p><strong>Sprint 1 — Nền tảng &amp; Hạ tầng</strong> ✅</p><ul><li>Mono-repo (Web + App + Doc)</li><li>Prisma + Supabase Auth + middleware admin/public</li><li>Service layer convention</li></ul><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-1-nen-tang.md</code></p><p><strong>Sprint 2 — Quản trị Nội dung &amp; Điểm đến</strong> ✅</p><ul><li>CRUD destination / tour / hotel / room / region</li><li>Cloudinary upload + image management</li><li>Audit log (<code>ActivityLog</code>)</li></ul><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-2-quan-tri-diem-den/</code></p><h3 id="tang-2-—-revenue-path-sprint-3-4-doing-upcoming" tabindex="-1">Tầng 2 — Revenue path (Sprint 3-4, Doing/Upcoming) <a class="header-anchor" href="#tang-2-—-revenue-path-sprint-3-4-doing-upcoming" aria-label="Permalink to &quot;Tầng 2 — Revenue path (Sprint 3-4, Doing/Upcoming)&quot;">​</a></h3><p><strong>Sprint 3 — Khám phá &amp; Tìm kiếm</strong> 🔶 In Progress (~40%)</p><ul><li>Tour listing + filter (destination, giá, thời gian, mood)</li><li>Autocomplete + map cluster (chưa)</li><li>SSR/ISR + cache</li></ul><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/</code></p><p><strong>Sprint 4 — Đặt chỗ &amp; Thanh toán</strong> ⏳ Upcoming (10% stub)</p><ul><li><strong>Sprint quan trọng nhất Phase 1</strong> — sinh revenue</li><li>Booking flow: cart → form → payment → confirm</li><li>Pessimistic lock <code>TourDeparture.bookedCount</code></li><li>VNPay + MoMo integration</li><li><code>InquiryRequest</code> lead capture (Private Tour)</li><li>Cron auto-cancel booking PENDING quá 15 phút</li><li>Email transactional (Resend)</li></ul><p><strong>Pre-requisites cứng</strong> (phải xong TRƯỚC khi start):</p><ol><li>Migration <code>add_pricing_options_and_allotment</code> (10 PART) chạy thành công</li><li>Schema <code>@db.Uuid</code> toàn bộ ID/FK (ADR-003)</li><li><code>Booking.userId</code> + <code>Review.userId</code> chuyển <code>onDelete: Restrict</code></li><li>Doc: <code>03-co-so-du-lieu/03-toan-ven-concurrency.md</code> đã chốt</li></ol><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-4-dat-cho-thanh-toan/</code></p><h3 id="tang-3-—-retention-seo-sprint-5-6-upcoming" tabindex="-1">Tầng 3 — Retention &amp; SEO (Sprint 5-6, Upcoming) <a class="header-anchor" href="#tang-3-—-retention-seo-sprint-5-6-upcoming" aria-label="Permalink to &quot;Tầng 3 — Retention &amp; SEO (Sprint 5-6, Upcoming)&quot;">​</a></h3><p><strong>Sprint 5 — Thành viên &amp; Đánh giá</strong> ⏳</p><ul><li>User profile + booking history</li><li>Review verified (chỉ booking <code>COMPLETED</code>)</li><li>Profile portal <code>/account/*</code></li></ul><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-5-thanh-vien-danh-gia/</code></p><p><strong>Sprint 6 — Quy hoạch &amp; Tối ưu</strong> ⏳</p><ul><li>SEO toàn diện (Lighthouse &gt;90, Core Web Vitals)</li><li>Sitemap + robots.txt + structured data đầy đủ</li><li>Admin Dashboard L0 (booking hôm nay, doanh thu tuần, top tour, export CSV)</li><li>Performance optimize + cache tuning</li><li>Pre-launch checklist</li></ul><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-6-quy-hoach-toi-uu/</code></p><hr><h2 id="sequencing-—-vi-sao-theo-thu-tu-nay" tabindex="-1">Sequencing — vì sao theo thứ tự này <a class="header-anchor" href="#sequencing-—-vi-sao-theo-thu-tu-nay" aria-label="Permalink to &quot;Sequencing — vì sao theo thứ tự này&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Quyết định</th><th>Lý do</th></tr></thead><tbody><tr><td><strong>Booking-first</strong> (Sprint 4 trước Sprint 5)</td><td>Sinh revenue. Review schema có sẵn nhưng UI có thể defer 1 sprint mà không chặn launch</td></tr><tr><td><strong>CMS trước Discovery</strong></td><td>Admin cần tạo tour để có data hiển thị; Sprint 3 dùng data Sprint 2</td></tr><tr><td><strong>SEO Sprint 6, không phải Sprint 1</strong></td><td>Foundation SEO (metadata, sitemap) có từ Sprint 1; optimize Lighthouse Sprint 6 khi data đủ</td></tr><tr><td><strong>Optimize cuối cùng</strong></td><td>Profiling cần production-like data → chạy trên data thật</td></tr><tr><td><strong>Inquiry chung Sprint 4</strong></td><td>Cùng touch booking + email + admin notification — gộp tránh duplicate</td></tr></tbody></table><hr><h2 id="milestones-deliverables" tabindex="-1">Milestones &amp; Deliverables <a class="header-anchor" href="#milestones-deliverables" aria-label="Permalink to &quot;Milestones &amp; Deliverables&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tháng</th><th>Milestone</th><th>Output</th></tr></thead><tbody><tr><td><strong>M1</strong> (now)</td><td>Migration <code>add_pricing_options_and_allotment</code> done</td><td>Schema UUID + 10 PART applied</td></tr><tr><td><strong>M2</strong></td><td>Sprint 3 Discovery close</td><td>Tour listing + filter prod-ready</td></tr><tr><td><strong>M3</strong></td><td>Sprint 4 Booking close</td><td>Booking flow end-to-end + 3 user beta</td></tr><tr><td><strong>M4</strong></td><td>Sprint 5 close</td><td>Review verified live, profile portal</td></tr><tr><td><strong>M5</strong></td><td>Sprint 6 close</td><td>Lighthouse &gt;90, Dashboard L0</td></tr><tr><td><strong>M6</strong></td><td><strong>Private beta launch</strong></td><td>20 tour + 3-5 user thật + Founder go-live</td></tr></tbody></table><hr><h2 id="risk-to-schedule" tabindex="-1">Risk to schedule <a class="header-anchor" href="#risk-to-schedule" aria-label="Permalink to &quot;Risk to schedule&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Risk</th><th>Tác động</th><th>Mitigation</th></tr></thead><tbody><tr><td>Migration <code>add_pricing_options_and_allotment</code> fail rollback</td><td>Block Sprint 4 → mất 1-2 tuần</td><td>Test trên DB staging copy production trước, script audit pre-flight</td></tr><tr><td>VNPay/MoMo sandbox không stable</td><td>Block Sprint 4 acceptance</td><td>Sandbox sớm Sprint 3 cuối, mock fallback</td></tr><tr><td>SEO traffic không lên đúng kỳ vọng</td><td>Phase 1.5 lùi</td><td>Dồn Ads budget bù 6-12 tháng đầu</td></tr><tr><td>Hotel partner không đủ 20 tour</td><td>Phase 1 launch trì hoãn</td><td>Founder track contract weekly, có buffer 30%</td></tr><tr><td>Team scale: 2 dev không kịp</td><td>Sprint trễ 2-3 tuần</td><td>Đã chấp nhận trade-off scope, không scope creep</td></tr></tbody></table><hr><h2 id="build-vs-buy-—-quyet-đinh-phase-1" tabindex="-1">Build vs Buy — quyết định Phase 1 <a class="header-anchor" href="#build-vs-buy-—-quyet-đinh-phase-1" aria-label="Permalink to &quot;Build vs Buy — quyết định Phase 1&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Build / Buy</th><th>Lý do</th></tr></thead><tbody><tr><td>Auth</td><td><strong>Buy</strong> (Supabase Auth)</td><td>Free tier đủ, không build custom — security risk</td></tr><tr><td>Payment</td><td><strong>Buy</strong> (VNPay + MoMo SDK)</td><td>Bắt buộc — không có lựa chọn build</td></tr><tr><td>Email transactional</td><td><strong>Buy</strong> (Resend)</td><td>Free tier 3k/tháng đủ phase 1</td></tr><tr><td>Image hosting</td><td><strong>Buy</strong> (Cloudinary)</td><td>Free tier đủ, optimize tự động</td></tr><tr><td>Analytics</td><td><strong>Buy</strong> (PostHog free / Plausible)</td><td>Build từ 0 mất 2-3 sprint</td></tr><tr><td>Search</td><td><strong>Build</strong> (Postgres full-text)</td><td>Phase 1 chưa cần Algolia/Meilisearch — Postgres đủ với &lt;1k tour</td></tr><tr><td>CMS</td><td><strong>Build</strong> (Next.js admin portal)</td><td>Off-the-shelf CMS không hợp model tour</td></tr><tr><td>Dashboard L0</td><td><strong>Build</strong></td><td>Đơn giản, query Prisma + render. L1/L2 sau cân nhắc buy</td></tr></tbody></table><hr><h2 id="resource-phase-1" tabindex="-1">Resource Phase 1 <a class="header-anchor" href="#resource-phase-1" aria-label="Permalink to &quot;Resource Phase 1&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Vai trò</th><th>FTE</th><th>Trách nhiệm</th></tr></thead><tbody><tr><td>Founder</td><td>1.0</td><td>Vision, contract hotel/partner, sales, GTM</td></tr><tr><td>Tech Lead / Senior Dev</td><td>1.0</td><td>Architecture, DB, code review, mentor</td></tr><tr><td>Dev (mid/junior)</td><td>1-2</td><td>Feature implementation theo sprint</td></tr><tr><td>Content / Ops (part-time)</td><td>0.5</td><td>Upload tour, viết SEO content, hỗ trợ khách</td></tr><tr><td>Designer (freelance)</td><td>0.2</td><td>UI Figma + component spec</td></tr></tbody></table><p><strong>Tổng</strong>: 3-5 FTE Phase 1. Phase 1.5 cân nhắc thêm 1 marketer + 1 customer support.</p><hr><h2 id="lien-ket" tabindex="-1">Liên kết <a class="header-anchor" href="#lien-ket" aria-label="Permalink to &quot;Liên kết&quot;">​</a></h2><ul><li>Vision: <code>01-tam-nhin.md</code></li><li>Mô hình kinh doanh: <code>02-mo-hinh-kinh-doanh.md</code></li><li>Personas: <code>03-personas-user-journey.md</code></li><li>Sprint folders: <code>../05-quan-ly-sprint/</code></li><li>Trạng thái triển khai web: <code>../05-quan-ly-sprint/trang-thai-web.md</code></li><li>Backlog chi tiết: <code>../05-quan-ly-sprint/backlog-chi-tiet.md</code></li></ul>`,62)])])}const g=n(o,[["render",r]]);export{u as __pageData,g as default};
